INSERT INTO rooms (room_number, type, price_per_night, capacity, description, image_path) VALUES
('101', 1, 15000, 1, 'Барлық базалық қолайлылықтары бар жайлы бір орындық нөмір. Жеке саяхатшылар үшін өте қолайлы.', 'images/rooms/room1.jpg'),
('102', 1, 20000, 2, 'Бір үлкен төсегі (King Size) және жеке жуынатын бөлмесі бар стандартты екі орындық нөмір.', 'images/rooms/room2.jpg'),
('103', 1, 20000, 2, 'Екі бөлек төсегі (Twin) бар стандартты екі орындық нөмір. Жарық әрі кең.', 'images/rooms/room3.jpg'),
('104', 1, 18000, 1, 'Ыңғайлы жұмыс аймағы және жылдам Wi-Fi бар іскерлік сапарларға арналған арнайы бір орындық нөмір.', 'images/rooms/room4.jpg'),
('105', 1, 25000, 3, 'Шағын компанияға немесе баласы бар отбасыға арналған үш орындық стандартты нөмір.', 'images/rooms/room5.jpg'),
('201', 2, 40000, 2, 'Қаланың панорамалық көрінісі, шағын бар және демалыс аймағы бар кең Делюкс нөмірі.', 'images/rooms/room6.jpg'),
('202', 2, 45000, 3, 'Отбасылық Делюкс нөмірі. Екі кісілік төсек және жайлы жиналмалы диван кіреді.', 'images/rooms/room7.jpg'),
('203', 2, 40000, 2, 'Эксклюзивті интерьер дизайны және тропикалық душы бар жақсартылған екі орындық нөмір.', 'images/rooms/room8.jpg'),
('204', 2, 55000, 4, 'Максималды жайлылық үшін екі іргелес бөлмесі бар кең отбасылық Делюкс.', 'images/rooms/room9.jpg'),
('301', 3, 90000, 2, 'Бөлек қонақ бөлмесі, джакузи және премиум косметикасы бар сәнді люкс.', 'images/rooms/room10.jpg'),
('302', 3, 150000, 4, 'Екі жатын бөлмесі, кең қонақ бөлмесі және терезеден керемет көрінісі бар президенттік люкс.', 'images/rooms/room11.jpg'),
('303', 3, 100000, 2, 'Балдахин төсегі және қонақ үйден комплименті бар жас жұбайларға арналған романтикалық люкс.', 'images/rooms/room12.jpg');
INSERT INTO rooms (room_number, type, price_per_night, capacity, description, image_path) VALUES
('101', 1, 15000, 1, 'Уютный одноместный номер со всеми базовыми удобствами. Идеально подходит для индивидуальных путешественников.', 'images/rooms/room1.jpg'),
('102', 1, 20000, 2, 'Стандартный двухместный номер с одной большой кроватью (King Size) и собственной ванной комнатой.', 'images/rooms/room2.jpg'),
('103', 1, 20000, 2, 'Стандартный двухместный номер с двумя раздельными кроватями (Twin). Светлый и просторный.', 'images/rooms/room3.jpg'),
('104', 1, 18000, 1, 'Специальный одноместный номер для деловых поездок с удобной рабочей зоной и быстрым Wi-Fi.', 'images/rooms/room4.jpg'),
('105', 1, 25000, 3, 'Трехместный стандартный номер для небольшой компании или семьи с ребенком.', 'images/rooms/room5.jpg'),
('201', 2, 40000, 2, 'Просторный номер Делюкс с панорамным видом на город, мини-баром и зоной отдыха.', 'images/rooms/room6.jpg'),
('202', 2, 45000, 3, 'Семейный номер Делюкс. Включает двуспальную кровать и комфортный раскладной диван.', 'images/rooms/room7.jpg'),
('203', 2, 40000, 2, 'Улучшенный двухместный номер с эксклюзивным дизайном интерьера и тропическим душем.', 'images/rooms/room8.jpg'),
('204', 2, 55000, 4, 'Просторный семейный Делюкс с двумя смежными комнатами для максимального комфорта.', 'images/rooms/room9.jpg'),
('301', 3, 90000, 2, 'Роскошный люкс с отдельной гостиной зоной, джакузи и премиальной косметикой.', 'images/rooms/room10.jpg'),
('302', 3, 150000, 4, 'Президентский люкс с двумя спальнями, просторной гостиной и потрясающим видом из окна.', 'images/rooms/room11.jpg'),
('303', 3, 100000, 2, 'Романтический люкс для молодоженов с кроватью с балдахином и комплиментом от отеля.', 'images/rooms/room12.jpg');